+    #[test]
+    fn edge_function_unit_triangle_area() {
+        // edge_function: (c.x-a.x)*(b.y-a.y) - (c.y-a.y)*(b.x-a.x)
+        // For (0,0),(1,0),(0,1): (0)*(0) - (1)*(1) = -1
+        let a = [0.0, 0.0, 0.0];
+        let b = [1.0, 0.0, 0.0];
+        let c = [0.0, 1.0, 0.0];
+        let area = edge_function(a, b, c);
+        assert!(
+            (area - (-1.0)).abs() < 1e-5,
+            "unit right triangle should have signed area -1.0, got {area}"
+        );
+    }
